// ─── Physics Sanity Checks ──────────────────────────────────────────

describe('physics sanity checks', () => {
  it('two events at the same location and time have ds² = 0', () => {
    const interval = spacetimeInterval(earth, { ...earth, id: 'earth-copy' });
    expect(Math.abs(interval.dsSquared)).toBeLessThan(1e-10);
  });

  it('spacelike interval has positive ds²', () => {
    const interval = spacetimeInterval(earth, proxima);
    expect(interval.dsSquared).toBeGreaterThan(0);
  });

  it('timelike interval has negative ds²', () => {
    const interval = spacetimeInterval(earth, futureEarth);
    expect(interval.dsSquared).toBeLessThan(0);
  });

  it('proper time of stationary observer equals coordinate time', () => {
    const interval = spacetimeInterval(earth, futureEarth);
    // Both at origin, 1 pLo apart -> proper time = 1 pLo
    expect(interval.properTimePLo).toBeCloseTo(1, 3);
  });

  it('proper distance of simultaneous events equals spatial distance', () => {
    const interval = spacetimeInterval(earth, proxima);
    // Same time, 4.24 ly apart -> proper distance = 4.24 ly
    expect(interval.properDistanceLy).toBeCloseTo(4.24, 1);
  });

  it('interval is symmetric in classification', () => {
    const ab = spacetimeInterval(earth, proxima);
    const ba = spacetimeInterval(proxima, earth);
    expect(ab.classification).toBe(ba.classification);
    // ds² is invariant under exchange (signs of dt and dx both flip)
    expect(Math.abs(ab.dsSquared - ba.dsSquared)).toBeLessThan(1e-6);
  });

  it('triangle inequality: if A→B timelike and B→C timelike, then A→C timelike', () => {
    // Earth now → Earth +1 pLo → Earth +2 pLo
    const earthPlus2: SpacetimeEvent = {
      id: 'earth+2', label: 'Earth +2', x: 0, y: 0, z: 0, pLo: NOW_PLO + 2,
    };
    const ab = spacetimeInterval(earth, futureEarth);
    const bc = spacetimeInterval(futureEarth, earthPlus2);
    const ac = spacetimeInterval(earth, earthPlus2);
    expect(ab.classification).toBe('timelike');
    expect(bc.classification).toBe('timelike');
    expect(ac.classification).toBe('timelike');
    // Twin paradox: proper time along straight path ≥ sum of proper times along bent path
    // For straight worldlines this is equality
    expect(ac.properTimePLo).toBeCloseTo(
      ab.properTimePLo! + bc.properTimePLo!,
      3
    );
  });
});
